changeSet.sql:
UPDATE clinlims.test SET loinc = '2345-7', lastupdated = now()
    WHERE name = 'Glucose' AND (loinc IS NULL OR loinc = '');
UPDATE clinlims.test SET loinc = '2160-0', lastupdated = now()
    WHERE name = 'Creatinine' AND (loinc IS NULL OR loinc = '');

rollback.sql:
DELETE FROM clinlims.test
    WHERE name IN ('Blood Urea Nitrogen', 'Aspartate Aminotransferase', 'Alanine Aminotransferase', 'Total Protein')
    AND loinc IN ('3094-0', '1920-8', '1742-6', '2885-2');

DELETE FROM clinlims.analyzer_test_map
    WHERE analyzer_test_name IN ('GLU', 'BUN', 'CREA', 'AST', 'ALT', 'TP')
    AND analyzer_id IN (SELECT id FROM clinlims.analyzer WHERE name = 'Seamaty SD1');
